"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[718],{7833:e=>{e.exports=JSON.parse('{"lang":"de","resources":{"landing":{"meta":{"title":"Linguist \u2013 Webseiten privat \xfcbersetzen | Browser-\xdcbersetzer-Erweiterung f\xfcr Chrome & Firefox","description":"Eine datenschutzfreundliche Browser-Erweiterung f\xfcr Chrome und Firefox. Webseiten, markierte Texte, Untertitel und Nachrichten lassen sich in Sekundenschnelle \xfcbersetzen. Funktioniert offline und unterst\xfctzt die Integration von \xdcbersetzungsdiensten und APIs."},"navigation":{"features":{"content":"Funktionen"},"blog":{"content":"Blog"},"docs":{"content":"Dokumentation"},"github":{"content":"GitHub"}},"install":{"chrome":"F\xfcr Chrome installieren","firefox":"F\xfcr Firefox installieren"},"sections":{"hero":{"title":"Webseiten nahtlos \xfcbersetzen","description":"Linguist ist ein flexibler Browser-\xdcbersetzer, der die beliebtesten \xdcbersetzungsdienste nutzt.\\n\\nGanze Webseiten, markierte Texte, Untertitel auf Netflix oder in Video-Calls sowie private Nachrichten lassen sich m\xfchelos \xfcbersetzen. \xdcbersetzungen k\xf6nnen angeh\xf6rt und im pers\xf6nlichen W\xf6rterbuch gespeichert werden, um auch offline neue Vokabeln zu lernen.\\n\\nLinguist ist eine moderne und datenschutzfreundliche Alternative zur Google \xdcbersetzer-Erweiterung. Jetzt kostenlos ausprobieren."},"opensource":{"title":"Open Source","content":"Linguist ist eine kostenlose <0>Open-Source</0>-Erweiterung zum \xdcbersetzen im Browser. Es werden keine Nutzerdaten gesammelt oder verkauft.\\n\\nMit einer <1>Spende</1> l\xe4sst sich Linguist unterst\xfctzen, damit das Projekt unabh\xe4ngig bleibt und die hohe Qualit\xe4t erhalten wird.\\n\\nTeilen Sie Linguist gerne in den sozialen Netzwerken, damit auch andere davon profitieren k\xf6nnen."},"support":{"title":"Support","content":"Bei Fragen k\xf6nnen Sie uns gerne kontaktieren <0/>.\\nFalls Sie einen Fehler gefunden haben und \xfcber ein GitHub-Konto verf\xfcgen, <1>erstellen Sie bitte ein Issue</1>."},"createdBy":{"content":"Entwickelt von <0/>."}},"features":{"title":"Funktionen","items":{"offlineTranslation":{"title":"Offline-\xdcbersetzung und Datenschutz","content":"Mit dem integrierten Offline-\xdcbersetzer lassen sich Texte direkt auf dem eigenen Ger\xe4t \xfcbersetzen. Die Inhalte bleiben privat und werden nicht \xfcber das Internet verschickt.\\n\\nDiese Funktion kann in den Einstellungen aktiviert werden, um sensible Daten in E-Mails, Dokumenten oder pers\xf6nlichen Nachrichten zu sch\xfctzen.\\n\\nZudem erm\xf6glicht der Offline-\xdcbersetzer das \xdcbersetzen von Webseiten ganz ohne Internetverbindung \u2013 besonders praktisch auf Reisen."},"fullPageTranslation":{"title":"Ganze Webseiten \xfcbersetzen","content":"Schnelle und hochwertige \xdcbersetzungen kompletter Webseiten mit nur wenigen Klicks.\\n\\nEin Tastenk\xfcrzel gen\xfcgt f\xfcr die sofortige \xdcbersetzung. F\xe4hrt man mit der Maus \xfcber den \xfcbersetzten Text, wird das Original angezeigt. Selbst private Seiten hinter Logins oder Paywalls lassen sich problemlos \xfcbersetzen.\\n\\nZudem k\xf6nnen automatische \xdcbersetzungsregeln basierend auf der Sprache oder Domain einer Webseite eingerichtet werden.\\n\\nLinguist greift dabei nur minimal in die Webseite ein: Es werden lediglich die Texte ausgetauscht, sodass das Layout und die Bedienbarkeit vollst\xe4ndig erhalten bleiben.\\n\\nF\xfcr internationale Meetings \xfcber Zoom, Google Meet und Microsoft Teams l\xe4sst sich au\xdferdem eine Echtzeit-\xdcbersetzung aktivieren."},"selectedTextTranslation":{"title":"Markierte Texte auf jeder Webseite \xfcbersetzen","content":"Unbekannte W\xf6rter in einem Online-Artikel entdeckt?\\nEinfach den entsprechenden Text auf der Seite markieren und auf den \xdcbersetzen-Button klicken.\\n\\nSowohl der Originaltext als auch die \xdcbersetzung k\xf6nnen angeh\xf6rt werden. Wichtige Begriffe lassen sich im W\xf6rterbuch speichern, um sie sp\xe4ter zu wiederholen."},"textTranslation":{"title":"Schnelle Text\xfcbersetzung","content":"Es muss schnell etwas \xfcbersetzt werden? Ein Klick auf das Linguist-Symbol gen\xfcgt, um den Text direkt einzugeben.\\n\\nDas Wechseln zwischen Tabs oder das Aufrufen von \xdcbersetzungs-Webseiten entf\xe4llt. Die \xdcbersetzung erfolgt direkt im Browser \u2013 mit dem bevorzugten \xdcbersetzungsdienst."},"knowledgeBase":{"title":"Eine pers\xf6nliche Wissensdatenbank aufbauen","content":"Jede \xdcbersetzung wird im Verlauf gespeichert, und besonders wichtige Begriffe k\xf6nnen dem pers\xf6nlichen W\xf6rterbuch hinzugef\xfcgt werden. Der Verlauf und das W\xf6rterbuch lassen sich jederzeit durchsuchen.\\n\\nSo geht auch bei l\xe4ngeren Recherchen oder Lerneinheiten nichts verloren.\\n\\nDa das W\xf6rterbuch auch offline funktioniert, ist Linguist der ideale Begleiter f\xfcr alle, die Sprachen lernen oder auf Reisen jederzeit Zugriff auf ihre Vokabeln ben\xf6tigen."},"customTranslators":{"title":"\xdcbersetzungsdienste und APIs integrieren","content":"Mit Linguist l\xe4sst sich der bevorzugte \xdcbersetzungsdienst frei w\xe4hlen.\\n\\nUnterst\xfctzt werden bekannte Anbieter wie Google, Yandex und Microsoft mit einer Auswahl von \xfcber 100 Sprachen.\\n\\nSollte ein gew\xfcnschter Dienst fehlen, kann dieser einfach als <0>benutzerdefinierter \xdcbersetzer</0> hinzugef\xfcgt werden.\\n\\nSo l\xe4sst sich jedes beliebige \xdcbersetzungssystem integrieren \u2013 von modernen KI-Diensten wie ChatGPT, DeepL, DeepSeek und Gemini bis hin zu lokalen \xdcbersetzern, die direkt auf dem eigenen Ger\xe4t laufen, wie etwa Ollama oder LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"Was ist Linguist?","content":"Linguist ist eine datenschutzfreundliche Browser-Erweiterung f\xfcr Chrome und Firefox.\\n\\nDamit lassen sich komplette Webseiten, markierte Texte, Untertitel und Nachrichten direkt im Browser \xfcbersetzen, ohne auf externe \xdcbersetzungs-Webseiten wechseln zu m\xfcssen."},"whyLinguist":{"title":"Warum sollte man Linguist nutzen?","content":"Es gibt viele Browser-Erweiterungen zum \xdcbersetzen von Webseiten, und einige Browser haben sogar integrierte \xdcbersetzer. Warum also Linguist?\\n\\nDie meisten integrierten \xdcbersetzer und Erweiterungen sind in ihrer Flexibilit\xe4t eingeschr\xe4nkt. Viele verlassen sich auf einen einzigen Anbieter wie Google \xdcbersetzer oder Microsoft Bing, w\xe4hrend Firefox einen eigenen Offline-\xdcbersetzer anbietet. In den meisten F\xe4llen l\xe4sst sich der Dienst nicht frei w\xe4hlen.\\n\\nWenn die \xdcbersetzungsqualit\xe4t f\xfcr den eigenen Bedarf nicht ausreicht oder das Senden privater Texte an Drittanbieter keine Option ist, bieten viele Tools keine gute Alternative.\\n\\nZudem konzentrieren sich viele Werkzeuge nur auf eine einzige Aufgabe. Einige \xfcbersetzen ganze Seiten, andere nur markierten Text.\\n\\nGleichzeitig sind einige Erweiterungen stark auf Monetarisierung ausgelegt. Funktionen wie der \xdcbersetzungsverlauf oder ein pers\xf6nliches W\xf6rterbuch erfordern oft ein Abonnement, und manchmal werden selbst grundlegende Dinge wie ein Dark Mode als Premium-Funktion verkauft.\\n\\nLinguist verfolgt einen anderen Ansatz. Es ist als praktisches und vielseitiges Werkzeug konzipiert. Der \xdcbersetzungsdienst kann frei gew\xe4hlt und jederzeit gewechselt werden, und es lassen sich sogar eigene, benutzerdefinierte \xdcbersetzer hinzuf\xfcgen.\\n\\nDar\xfcber hinaus vereint Linguist alles an einem Ort: Ganze Webseiten, markierte Texte, Untertitel und Nachrichten k\xf6nnen \xfcbersetzt werden, w\xe4hrend wichtige Begriffe im Verlauf und im pers\xf6nlichen W\xf6rterbuch gespeichert bleiben."},"theLinguistLogo":{"title":"Warum ist das Logo von Linguist der Turmbau zu Babel?","content":"Das Logo von Linguist ist vom <wiki>Turmbau zu Babel</wiki> inspiriert, einer der \xe4ltesten Geschichten \xfcber Sprache und Kommunikation.\\n\\nDer Erz\xe4hlung nach sprachen die Menschen einst dieselbe Sprache und versuchten, einen Turm bis in den Himmel zu bauen. Der Turm wurde nie vollendet, und die Menschheit wurde in viele verschiedene Sprachen aufgeteilt. Seitdem erschweren Sprachbarrieren oft die Verst\xe4ndigung.\\n\\nLinguist wurde entwickelt, um genau dieses Problem zu l\xf6sen.\\n\\nDer Turm zu Babel im Logo erinnert an diese Geschichte: viele Sprachen, viele Kulturen und das stetige menschliche Bem\xfchen, einander zu verstehen. Linguist hilft dabei, diese Br\xfccken zu bauen, indem es \xdcbersetzungen einfach, flexibel und direkt im Browser zug\xe4nglich macht.\\n\\nDas Logo spiegelt auch den Geist des Projekts wider. Linguist ist nicht einfach nur eine weitere Benutzeroberfl\xe4che f\xfcr den \u201eGoogle \xdcbersetzer\u201c. Es wird von Menschen entwickelt, denen Sprachen, Datenschutz und offene Technologien am Herzen liegen. Der Turm zu Babel steht f\xfcr Neugier, das Lernen und die Idee, dass sprachliche Vielfalt die Menschen zusammenbringen sollte, anstatt sie zu trennen."},"imageTranslation":{"title":"Warum \xfcbersetzt Linguist keine Texte in Bildern?","content":"Linguist konzentriert sich auf zuverl\xe4ssige und hochwertige \xdcbersetzungsfunktionen.\\n\\nWir haben verschiedene Ans\xe4tze zur \xdcbersetzung von Texten in Bildern untersucht. Derzeit liefern die meisten verf\xfcgbaren L\xf6sungen keine konsistenten Ergebnisse, insbesondere wenn sie direkt im Browser ausgef\xfchrt werden \u2013 was jedoch entscheidend ist, um die Privatsph\xe4re der Nutzer zu sch\xfctzen.\\n\\nAus diesem Grund bietet Linguist momentan keine Bild\xfcbersetzung an. Wir verzichten lieber auf Funktionen, die unseren Qualit\xe4tsstandards nicht entsprechen.\\n\\nSobald wir einen zuverl\xe4ssigen und datenschutzfreundlichen Weg finden, die Bild\xfcbersetzung umzusetzen, werden wir diese Funktion gerne hinzuf\xfcgen."},"howTranslatePages":{"title":"Wie \xfcbersetzt Linguist Webseiten?","content":"Linguist kann komplette Webseiten mit nur wenigen Klicks \xfcbersetzen. Die \xdcbersetzung l\xe4sst sich \xfcber den Button der Erweiterung oder ein Tastenk\xfcrzel starten.\\n\\nDer Originaltext bleibt dabei immer zug\xe4nglich. F\xe4hrt man mit der Maus \xfcber den \xfcbersetzten Text, wird das Original eingeblendet."},"offlineTranslation":{"title":"Kann Linguist Webseiten offline \xfcbersetzen?","content":"Ja. Linguist verf\xfcgt \xfcber einen integrierten Offline-\xdcbersetzer, mit dem sich Texte \xfcbersetzen lassen, ohne Daten \xfcber das Internet zu senden.\\n\\nDas sch\xfctzt die Privatsph\xe4re und erm\xf6glicht es, Inhalte auch ganz ohne Internetverbindung zu \xfcbersetzen."},"privacy":{"title":"Sch\xfctzt Linguist meine Privatsph\xe4re?","content":"Ja. Linguist wurde mit einem starken Fokus auf Datenschutz entwickelt.\\n\\nDie Erweiterung sammelt oder verkauft keine Nutzerdaten. Bei der Nutzung des <offline-translator>Offline-\xdcbersetzers</offline-translator> werden alle \xdcbersetzungen vollst\xe4ndig lokal auf dem eigenen Ger\xe4t verarbeitet."},"supportedBrowsers":{"title":"Welche Browser werden von Linguist unterst\xfctzt?","content":"Linguist ist f\xfcr Chrome und Firefox verf\xfcgbar. Es funktioniert auch in anderen Chromium-basierten Browsern, die Chrome-Erweiterungen unterst\xfctzen.\\n\\nDar\xfcber hinaus l\xe4sst sich Linguist in Android-Browsern nutzen, die Erweiterungen zulassen, wie beispielsweise Firefox f\xfcr Android und einige Chromium-basierte Browser."},"selectedText":{"title":"Kann Linguist markierten Text \xfcbersetzen?","content":"Ja. Einfach den gew\xfcnschten Text auf einer beliebigen Webseite markieren und den \xdcbersetzen-Button nutzen, um ihn sofort zu \xfcbersetzen.\\n\\nDie \xdcbersetzung kann zudem angeh\xf6rt und im pers\xf6nlichen W\xf6rterbuch gespeichert werden."},"customTranslators":{"title":"Kann ich meinen eigenen \xdcbersetzungsdienst nutzen?","content":"Ja. Linguist unterst\xfctzt <custom-translator>benutzerdefinierte \xdcbersetzer</custom-translator>, mit denen sich weitere \xdcbersetzungsdienste integrieren lassen.\\n\\nSo k\xf6nnen externe APIs oder lokale \xdcbersetzungssysteme wie <libre-translate>LibreTranslate</libre-translate> oder <ollama>Ollama</ollama> angebunden werden."},"isFree":{"title":"Ist Linguist kostenlos?","content":"Ja. Linguist ist vollst\xe4ndig kostenlos und <linguist>Open Source</linguist>.\\n\\nDas Projekt wird von der Community getragen und kann optional <donations>mit einer Spende unterst\xfctzt werden</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bg","langName":"\u0431\u044a\u043b\u0433\u0430\u0440\u0441\u043a\u0438","url":"https://linguister.io/bg"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"ca","langName":"catal\xe0","url":"https://linguister.io/ca"},{"langCode":"cs","langName":"\u010de\u0161tina","url":"https://linguister.io/cs"},{"langCode":"da","langName":"dansk","url":"https://linguister.io/da"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"el","langName":"\u0395\u03bb\u03bb\u03b7\u03bd\u03b9\u03ba\u03ac","url":"https://linguister.io/el"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fa","langName":"\u0641\u0627\u0631\u0633\u06cc","url":"https://linguister.io/fa"},{"langCode":"fi","langName":"suomi","url":"https://linguister.io/fi"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"he","langName":"\u05e2\u05d1\u05e8\u05d9\u05ea","url":"https://linguister.io/he"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"hu","langName":"magyar","url":"https://linguister.io/hu"},{"langCode":"id","langName":"Indonesia","url":"https://linguister.io/id"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ka","langName":"\u10e5\u10d0\u10e0\u10d7\u10e3\u10da\u10d8","url":"https://linguister.io/ka"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"nb","langName":"norsk bokm\xe5l","url":"https://linguister.io/nb"},{"langCode":"nl","langName":"Nederlands","url":"https://linguister.io/nl"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pl","langName":"polski","url":"https://linguister.io/pl"},{"langCode":"pt-BR","langName":"portugu\xeas (Brasil)","url":"https://linguister.io/pt-BR"},{"langCode":"pt-PT","langName":"portugu\xeas europeu","url":"https://linguister.io/pt-PT"},{"langCode":"ro","langName":"rom\xe2n\u0103","url":"https://linguister.io/ro"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"sl","langName":"sloven\u0161\u010dina","url":"https://linguister.io/sl"},{"langCode":"sr","langName":"\u0441\u0440\u043f\u0441\u043a\u0438","url":"https://linguister.io/sr"},{"langCode":"sv","langName":"svenska","url":"https://linguister.io/sv"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"te","langName":"\u0c24\u0c46\u0c32\u0c41\u0c17\u0c41","url":"https://linguister.io/te"},{"langCode":"th","langName":"\u0e44\u0e17\u0e22","url":"https://linguister.io/th"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"uk","langName":"\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0430","url":"https://linguister.io/uk"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh-CN","langName":"\u4e2d\u6587\uff08\u4e2d\u56fd\uff09","url":"https://linguister.io/zh-CN"},{"langCode":"zh-TW","langName":"\u4e2d\u6587\uff08\u53f0\u7063\uff09","url":"https://linguister.io/zh-TW"}]}')}}]);